public int smallestNumberWithAtLeastOneDigitFromEachArray(int[] nums1, int[] nums2) {
    int min1 = Arrays.stream(nums1).min().getAsInt();
    int min2 = Arrays.stream(nums2).min().getAsInt();
    for (int num1 : nums1) {
        for (int num2 : nums2) {
            if (num1 == num2) {
                return num1;
            }
        }
    }
    return min1 * 10 + min2;
}
